inventory = {
    "laptop": {"price": 50000, "stock": 5},
    "mouse": {"price": 500, "stock": 20},
    "keyboard": {"price": 1500, "stock": 10}
}

def purchase_item(item_name, quantity):
    if item_name in inventory:
        inventory[item_name]["stock"] = inventory[item_name]["stock"] - quantity
        total_price = inventory[item_name]["price"] * quantity
        print("Purchased", quantity, item_name)
        print("Total:", total_price)
    else:
        print("Item not found")

def restock_item(item_name, quantity):
    if item_name in inventory:
        inventory[item_name]["stock"] = inventory[item_name]["stock"] + quantity

def display_inventory():
    for item, details in inventory.items():
        print(item, details)

purchase_item("laptop", 10)
purchase_item("mouse", 2)
restock_item("keyboard", 5)
display_inventory()

