class Library:
    def __init__(self):
        self.books = []

    def add_book(self, title, author):
        self.books.append({"title": title, "author": author, "issued": False})

    def issue_book(self, title):
        for book in self.books:
            if book["title"] == title and not book["issued"]:
                book["issued"] = True
                print(title, "issued successfully")
                return
        print(title, "not available")

    def return_book(self, title):
        for book in self.books:
            if book["title"] == title and book["issued"]:
                book["issued"] = False
                print(title, "returned successfully")
                return
        print(title, "was not issued")

    def show_books(self):
        for book in self.books:
            print(book)

lib = Library()
lib.add_book("Python Basics", "Guido")
lib.add_book("Data Science", "Andrew")
lib.issue_book("Python Basics")
lib.return_book("Python Basics")
lib.show_books()

output:
Python Basics issued successfully
Python Basics returned successfully
{'title': 'Python Basics', 'author': 'Guido', 'issued': False}
{'title': 'Data Science', 'author': 'Andrew', 'issued': False}

