async function fetchUser(id) {
  let retries = 3;

  while (retries >= 0) {
    try {
      const res = fetch(`https://jsonplaceholder.typicode.com/users/${id}`);

      if (!res.ok) {
        throw new Error("Request failed");
      }

      const data = await res.json();
      return data.name.toUpperCase();
    } catch (err) {
      retries--;
    }
  }

  return null;
}

fetchUser(1).then(console.log);

