let balance = 1000;

async function withdraw(amount) {
  if (balance >= amount) {
    await new Promise(resolve => setTimeout(resolve, 100));
    balance = balance - amount;
    return true;
  }
  return false;
}

async function run() {
  await Promise.all([
    withdraw(700),
    withdraw(700)
  ]);

  console.log("Final balance:", balance);
}

run();

