import java.util.ArrayList;

class Order {
    String customer;
    double amount;

    Order(String customer, double amount) {
        this.customer = customer;
        this.amount = amount;
    }
}

public class Main {
    public static void main(String[] args) {
        ArrayList<Order> orders = new ArrayList<>();

        orders.add(new Order("Amit", 1000));
        orders.add(new Order("Riya", 2000));
        orders.add(new Order("Kunal", -500));

        double total = 0;

        for (Order order : orders) {
            total += order.amount;
        }

        System.out.println("Total order amount: " + total);
    }
}

